// GCC Church — Alarm Sounds (base64 WAV)
const ALARM_SOUND_B64 = "";
const VERSE_SOUND_B64 = "";

function playAlarmSound(type) {
  try {
    const b64  = type === 'verse' ? VERSE_SOUND_B64 : ALARM_SOUND_B64;
    const bin  = atob(b64);
    const buf  = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i);
    const blob = new Blob([buf], { type: 'audio/wav' });
    const url  = URL.createObjectURL(blob);
    const audio = new Audio(url);
    audio.volume = 1.0;
    audio.play().catch(() => {});
    setTimeout(() => URL.revokeObjectURL(url), 5000);
  } catch(e) {
    console.warn('Alarm sound error:', e);
  }
}

window.playAlarmSound = playAlarmSound;
